// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../../../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校園長廊是鳴海高中最安靜的地方之一。走廊兩側是紅磚拱柱，頂上爬滿了老藤，葉子被上午的雨洗得發亮，陽光還沒有出來，但天空比上午亮了一些，灰白色裡透出一點淡淡的藍。走在這裡，腳步聲會被拱頂回彈，產生一種輕微的共鳴，像有人在旁邊跟著你走。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "長廊的盡頭能看到鐘樓。距離不近，但鐘樓太高了，在這個校園裡幾乎從任何角度都逃不掉它的輪廓。此刻它灰撲撲地矗在遠處，頂上的鐘面朝著天空，指針看不見，但你知道它們在走。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十二點半。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從校史館出來已經快二十分鐘了。下午兩點才有志工排班，中間這段空檔他不知道該做什麼。回宿舍太遠，食堂太吵，操場在搭舞台，到處都是人。長廊是少數還算安靜的地方——因為它不在主要活動動線上，校慶的熱鬧暫時還沒有蔓延到這裡。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔說把那條訊息的事交給他。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那就交給他。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯可是「相機」是什麼意思？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他靠在一根紅磚拱柱上，雙手插在外套口袋裡。口袋右邊是手機，手機裡是那條訊息。他已經看了很多遍了，多到每個字都可以默寫出來。「今晚 22:22，鐘樓會停電。不要上去。不要把相機交給任何大人。」時間、地點、警告——前三句他都理解。但「相機」不一樣。相機是具體的。相機是一個物件。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我家裡沒有相機。爸的東西在火災之後就沒什麼留下來了。就算有，也不會在學校。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他正想著，餘光捕捉到一個動作。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "長廊的另一端，靠近校史館側門的方向，有一個人影。準確地說，是一個舉著相機的人影。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是個女生。穿著校服，但外面套了一件深灰色的攝影背心，背心上別著一個小小的藍色工作證。她半蹲著，相機舉在眼前，鏡頭的方向——", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她在拍我？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的第一反應是身體微微繃緊。不是害怕，是一種被注視時的本能警覺，像貓的耳朵突然豎起來。他下意識地想轉身避開鏡頭，但動作做到一半就停住了。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不對。她不是在拍我。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的鏡頭方向比他的位置更偏右。偏右很多。他順著她的鏡頭方向看過去——那邊是校園主道，主道盡頭是臨時指揮室的活動板房。距離很遠，但隱約能看到板房門口有人進出。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她在拍指揮室？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的眉頭皺了一下。長廊的位置很好，正好是一個半隱蔽的觀察點——紅磚拱柱提供了遮擋，但視線可以穿過拱門之間的間隙看到主道。如果有人在這裡拍照，被拍的人很難注意到。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)校慶的時候到處都有人在拍照，這不奇怪。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但她拍的不是校慶。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他觀察了幾秒。那個女生又換了一個姿勢，從半蹲變成站著，身體微微前傾，鏡頭向下壓了一個角度。這一次她的方向更偏了，朝著主道中段——那裡剛好有兩個人並肩走過。一個穿深藍制服的警察，一個穿深灰西裝的中年男人。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔和林主任。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她在拍他們。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯為什麼？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從拱柱後面走出來，朝那個女生的方向走去。腳步不快，但路線很直。他的鞋踩在長廊的石板地面上，聲音被拱頂回彈，她不可能聽不到。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她確實聽到了。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在顧言走到距離她大約五步遠的時候，她放下了相機。動作很自然，不慌不忙，像一個人結束了一項工作，隨手把工具收起來。她沒有轉身，也沒有回頭看，只是把相機的灰色背帶繞在手腕上，站直了身體。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她轉過來了。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "臉很小，五官清瘦，皮膚是那種不怎麼曬太陽的白。頭髮紮成低馬尾，幾根碎髮貼在耳側，被雨後的濕氣黏住了。眼睛是黑的，瞳仁很亮，但不是那種熱情的亮，是一種安靜的、像深水一樣的東西——你看得到表面，猜不到深度。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看了顧言一眼。只有一眼。然後她的視線就從他臉上移開了，落在他肩膀後方的某個位置，像在確認他有沒有帶別人來。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "拍什麼？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的語氣不重，但也不友好。更像是質問，而不是寒暄。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有回答。她把相機的鏡頭蓋從口袋裡掏出來，扣上，動作很熟練，像做了一百次。然後她重新看了他一眼，這一次看得久了一點，大概兩秒。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你是顧言。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.XuXingtang_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是疑問句。是陳述句。她的聲音偏低，語速不快，每個字的發音都很清楚，像刻意控制過音量——不會大到被第三個人聽見，也不會小到讓對方聽不清。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她知道我的名字。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "你是誰？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "許星棠。校慶文檔組的攝影。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.XuXingtang_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說「文檔組的攝影」這幾個字的時候，語氣和說自己名字一樣平淡，不帶任何多餘的情緒。像是遞過來一張名片，你看完就可以扔了。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)文檔組。校慶文檔組負責記錄整個校慶活動的影像資料，攝影師都是從各班選出來的學生。這不奇怪。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但文檔組的人應該在拍校慶活動。她在拍指揮室、拍邵叔、拍林主任。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "拍人？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你收到訊息了。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.XuXingtang_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有接他的話。甚至沒有停頓一下作為過渡。她直接跳到了另一個問題，像一個人翻頁的時候直接跳過了三個章節。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)——", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)什麼？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她怎麼知道訊息的事？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的表情沒有變。他的臉還是那張缺乏表情的臉，平得像一面沒有掛畫的牆。但他的瞳孔縮了一下。這個變化很小，小到只有靠得很近、而且很仔細看的人才能發現。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠靠得很近。而且她看得很仔細。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "什麼訊息？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的聲音沒有波動。回答得很快，快到像是提前準備好的。這是一種保護性的反應——遇到未知的威脅時，先否認，先縮小暴露面。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠沒有被他騙到。或者說，她根本不在乎他否不否認。她只是微不可察地點了一下頭，幅度小到像是在確認自己的某個判斷，而不是在回應他。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "今天不要靠近鐘樓。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.XuXingtang_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的語氣和剛才一樣平。沒有警告的急迫感，沒有關心的溫度，沒有神祕人的故弄玄虛。就是一句話，平鋪直敘，像在說「今天不要忘記帶傘」。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)鐘樓。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)訊息裡也提到了鐘樓。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她知道訊息的內容。她一定知道。她要嘛是發訊息的人，要嘛和發訊息的人有關。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "你是誰？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "我說了。許星棠。文檔組。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.XuXingtang_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不是這個。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的聲音壓低了半個音階。不是刻意威脅，是一種接近防禦狀態的本能——他感覺到對面的這個人知道一些他不知道的東西，而這種信息不對等讓他渾身不自在。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "還有。不管誰說要幫你保管相機，都不要給。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.XuXingtang_Urgent },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說這句話的時候，眼神有了一點變化。不是大的變化，不是從冷到熱、從遠到近那種。是一種更細微的東西——像深水底下有什麼東西動了一下，水面沒有波紋，但你知道底下不是靜止的。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)相機。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)又是相機。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)訊息裡的第四個詞。她單獨提到了相機。她知道有一台相機。她知道有人會來拿這台相機。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "什麼相機？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他問這句話的時候，是真的困惑。他不知道什麼相機。他家裡沒有相機。他父親的遺物裡沒有相機。他從來沒有擁有過一台相機。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠聽到這個問題之後，臉上出現了一個很短的表情。那個表情持續了不到一秒，像一扇窗被風吹開又立刻被按住——裡面是什麼，來不及看清楚。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她後悔了。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她說了不該說的話。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的嘴唇抿了一下。她的手指收緊了相機背帶，指節微微發白。然後她把目光從顧言身上移開，看向長廊的另一端。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯忘了我說的。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.XuXingtang_Regretful },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音比剛才更低了。低到像是在對自己說話。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)忘了？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)你告訴我不要靠近鐘樓、不要把相機交給任何人，然後你叫我忘了？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "回答我。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他往前邁了半步。距離拉近到了三步以內。這個距離在社交上已經屬於偏近了，帶著一種無聲的壓力。但許星棠沒有退。她甚至沒有看他，只是把相機背帶從手腕上取下來，掛回了脖子上。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你問的問題，我沒有答案。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.XuXingtang_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說完這句話就轉身了。動作乾脆，像一個在會議上說完自己意見就起身離開的人。她的背影很瘦，攝影背心在校服外面顯得有些寬大，肩膀撐不起來，讓整個人看起來比實際年齡小了一點。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她是發訊息的人。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一定是。她知道訊息的內容，她知道鐘樓，她知道相機。她知道我的名字。她知道我收到了那條訊息。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她到底想要什麼？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有追上去。不是因為不想，是因為一個聲音從長廊的另一端傳了過來。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "許星棠！", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音不大，但穿透力很強。那是一個男生的聲音，帶著一種急切的、像是被壓抑了很久才釋放出來的力道。聽起來像是在呵斥，像是在警告，像是在威脅——像一個人對另一個人說「你最好給我站住」。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那是誰？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉頭看向聲音的方向。長廊盡頭的拱門下面站著一個男生，校服外面套了一件沾了灰塵的深色外套，脖子上有什麼東西在晃——一條掛繩，掛繩下面是一張塑封的臨時通行證，藍底白字，上面印著「舞台組」。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "妳不能再一個人去。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說這句話的時候，臉上的表情很複雜。皺著眉，嘴唇壓得很緊，下巴微微抬起。看起來像是生氣，但如果只聽聲音不看他臉的話，那句話的語氣更接近於——擔心。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)「不能再一個人去」。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)去哪裡？她去了哪裡？為什麼不能一個人去？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠聽到那個聲音之後，腳步頓了一下。很小的停頓，像踩到了一顆小石子。然後她繼續往前走，沒有回頭，沒有應聲。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個男生——韓越——快步走了過來。他走路的姿勢有點不對，右手的擺動幅度比左手小，像是在避免碰到什麼。他經過顧言身邊的時候，顧言注意到了他的手。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他的手。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的手上有傷。不是擦傷，是刮傷——三五道平行的細痕，從手背延伸到指節，已經結了薄薄的痂，顏色偏暗紅，像被什麼粗糙的表面刮過。不是一天之內的新傷，但也沒有超過兩天。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)舞台組。臨時通行證。手上的刮傷。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他是舞台組的志工，負責搭建和搬運。刮傷可能是在搬東西的時候弄的。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)也可能不是。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越沒有理會顧言。他的注意力全部在許星棠身上。他加快腳步追了上去，在長廊的轉角處趕上了她。他們之間的距離很近，近到可以低聲說話而不被第三個人聽見。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有聽到他們後來說了什麼。他只看到韓越側過身，擋在了許星棠和長廊出口之間，像一堵不高但很堅決的牆。許星棠站在那裡，偏過頭，沒有看韓越，也沒有繞開他。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他們一起走了。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個人的背影在長廊的拱門下一前一後地消失。韓越走在前面，但不遠，每隔幾步就回頭看一眼，像在確認她還在跟著。許星棠走在後面，步伐不變，相機在胸前輕輕晃動。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)許星棠。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她知道我的名字。她知道訊息。她知道鐘樓。她知道相機。她在拍邵叔和林主任。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她是發訊息的人。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她要嘛是在幫我，要嘛是在設一個局。目前看起來更像後者。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)「今天不要靠近鐘樓」——如果她想害我，為什麼要叫我遠離？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)也許反過來想。她叫我不要去鐘樓，是因為她知道我一定會去。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她在試探我的反應。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他靠回拱柱上，雙手插在口袋裡。指尖碰到了手機的邊緣，冰涼的，像一個沉默的提醒。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)還有那個韓越。「妳不能再一個人去。」", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他看起來像是在威脅她。但他的表情不對。那不是威脅的表情。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他怕她出事。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他們之間有某種聯繫。不是同學那麼簡單。他叫她的全名，不是「星棠」也不是「許同學」，是「許星棠」。三個字，連名帶姓，距離感和親密感同時存在。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他的手。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)舞台組的通行證、手上的刮傷。他白天在舞台組工作，晚上呢？", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我想太多了。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)也許不夠多。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "長廊又安靜了。拱柱的影子在石板地面上拉得很長，午後的光線比上午亮了一些，但天空依然沒有放晴。遠處傳來校慶廣播的聲音，模模糊糊的，聽不清內容，只有斷斷續續的電流聲和偶爾飄過來的幾個字。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)許星棠說「不管誰說要幫你保管相機，都不要給」。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她說這句話的時候，像是知道有個人會來找我。會來拿一台我不知道的相機。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她知道即將發生的事。不只是鐘樓和訊息。她知道的比我以為的多。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但她說了「忘了我說的」。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她後悔了。她說多了，她知道她說多了。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一個在收集成年人行蹤的人，一個知道匿名訊息內容的人，一個說了太多又試圖收回的人。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她要嘛是敵人，要嘛是盟友。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不管是哪一個，她都太危險了。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從長廊裡走出來。風比剛才大了一點，吹動了校道兩側的彩旗和橫幅。他站在長廊的出口處，朝許星棠和韓越消失的方向看了一眼。什麼都看不到了，只有空蕩蕩的校道和遠處鐘樓的灰色輪廓。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)鐘樓。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)訊息說22:22。她說不要靠近。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)兩個人叫我遠離鐘樓。邵叔也叫我不准去。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)當所有人都叫你不要去一個地方的時候，通常有兩種可能。一是那個地方真的很危險。二是那個地方有什麼東西，有人不想讓你看見。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不管是哪一種，我都得去看看。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把手機從口袋裡拿出來，解鎖，打開那條訊息。螢幕的光映在他的臉上，灰色的天空在他身後，像一塊巨大的幕布。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)許星棠。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我不知道你是誰，不知道你想要什麼。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但你犯了一個錯誤。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)你不應該來找我。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)你一出現，就證明了這件事不只是惡作劇。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)你一出現，我就知道有人在背後看著我。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)而出現在我的視線裡的人，我是不會假裝沒看見的。", background: Background.Chapter_1_Ch1_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他關掉手機螢幕，收回口袋。轉身朝教學樓的方向走去。風把他的外套下擺吹得微微翻起，露出裡面深色的校服。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "長廊的紅磚拱柱在他身後一個接一個地退去，像一排沉默的旁觀者，什麼都看見了，什麼都不會說。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鐘樓的影子在遠處靜靜地立著。十二點半的鐘聲早已經響過了，但如果你仔細聽，風裡好像還殘留著最後一絲尾音。", background: Background.Chapter_1_Ch1_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有回頭。", background: Background.Chapter_1_Ch1_Act5_S0 },
];
